+fn parse_positive_dimension_arg(value: &str) -> std::result::Result<u32, String> {
+    let parsed = value
+        .parse::<u32>()
+        .map_err(|err| format!("invalid dimension '{value}': {err}"))?;
+    if parsed > 0 {
+        Ok(parsed)
+    } else {
+        Err(format!(
+            "invalid dimension '{value}': expected an integer greater than 0"
+        ))
+    }
+}
